@spec rm_metadata_spec  src=tests/specs/rm_metadata_spec.lua  loc=105  sha=e2be081  cases=5
@exercises harness (harness), configManager (h.cm)
@surface   harness.mk, cm:pollUndo
@harness   mk, reaper.CountTracks, reaper.InsertTrackAtIndex, reaper.GetTrack, reaper.GetSetMediaTrackInfo_String, reaper.GetTrackGUID, reaper:setFxIO, reaper.GetProjExtState, r._state.trackExt, r._state.projStateCount

# Intent
  rm metadata facility: non-native record fields persist behind the scenes —
  fx/bus-meta ride pextStore's undo mirror as ds keys; track-meta rides P_EXT.

# Helpers
  @fn mkRm()  @ 7-10
  @fn seedTrack(reaper, name)  @ 12-18
  @fn addFx(reaper, rm, tid, ident)  @ 20-23

# Cases
  @case 'track meta rides the track P_EXT and folds back onto the record'  [pure]  @ 27-37
  @case 'native-only fx write mints no scratch and stores no metadata'  [pure]  @ 40-50
  @case 'fx meta lives in projext, mirrors to scratch, folds onto records'  [pure]  @ 53-67
  @case 'fx-meta partial merge keeps earlier fields; util.REMOVE clears one'  [pure]  @ 70-83
  @case 'fx-meta rides undo: a rewound scratch mirror restores it through ds'  [pure]  @ 86-103

# Uses (outbound edges)
  @use call harness.mk  @ 8
  @use call cm:pollUndo  @ 101

# Fields (r read / w write incl. constructor keys)
  @field r REMOVE  @ 80,96
  @field r _state  @ 95,99,100
  @field w ds  @ 9
  @field r fx  @ 65
  @field r id  @ 65
  @field w ident  @ 22
  @field w ins  @ 21
  @field w name  @ 27,40,53,70,86
  @field w outs  @ 21
  @field w params  @ 46
  @field r pos  @ 32,35,61,77,82
  @field w pos  @ 31,58,75
  @field r projStateCount  @ 100
  @field w projStateCount  @ 100
  @field w run  @ 28,41,54,71,87
  @field r split  @ 36,49,60,66,78,81,97,102
  @field w split  @ 34,58,76,80,91,96
  @field r trackExt  @ 95
  @field w trackExt  @ 99
  @field w x  @ 31,32,35,58,61,75,77,82
  @field w y  @ 31,32,35,58,61,75,77,82
